var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"벌써 계약기간이 끝났군요. 시간이 정말 순식간에 지나가네요.","JPN":"もう契約期間満了ですか。本当にあっという間ですね。","ENG":"I can't believe our contract is coming to an end. Time really does fly by.","TWN":"合約這麼快就到期啦，時間過得還真快呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스를 이용해 주셔서 감사했습니다. 모쪼록 도움이 되었길 바랍니다.","JPN":"フローラメイドサービスをご利用いただきありがとうございました。お役に立てたのなら幸いです。","ENG":"Thank you for using Flora Maid Service. We hope we served you well.","TWN":"謝謝您利用芙蘿拉女僕的服務，希望有幫上您的忙。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그럼요. 큰 도움이 됐죠. 매년 이 시기만 되면 뜬눈으로 밤을 새우는 게 일상이었는데.","JPN":"もちろんです。おおいに助かりました。毎年この時期になると一睡もできなかったのに。","ENG":"Absolutely! It's become a habit of mine to stay up all night during this time of year.","TWN":"那當然，幫我很大的忙呢。每年只要到這個時候，熬夜根本是家常便飯。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"베로니카 씨 한 명이 우리 비서 서너 명보다 낫다니까요. 솔직히 반신반의했거든요.","JPN":"ベロニカさんの方が、うちの会社の秘書三～四人合わせたより役に立つわ。正直半信半疑だったけれど。","ENG":"I was skeptical at first, but... Veronica, you're better than four of my secretaries combined!","TWN":"我3、4個祕書都比不上貝洛妮卡你一個人，其實我原本還有點半信半疑呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"과찬이십니다.","JPN":"褒めすぎです。","ENG":"I'm flattered.","TWN":"您過獎了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네도 빨래하느라 무지 바빴지 말임다!","JPN":"モネも洗濯でめちゃくちゃ忙しかったっす！","ENG":"Mone was also busy doin' laundry, ma'am!","TWN":"莫妮也很努力洗衣服喔！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"모네도 고마웠어요. 유학 간 딸내미 같아서 참 보기 좋더라고요.","JPN":"モネもお疲れさまでした。留学中の娘を見ているようで本当に楽しかったわ。","ENG":"Thank you too, Mone. Having you around made me think about my daughter studying abroad right now.","TWN":"對，我也很謝謝莫妮，而且你和我去留學的女兒長得好像，看到你就開心。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 들으셨슴까! 모네 칭찬 받았슴다!","JPN":"メイド長、聞いたっすか！　モネ、褒めてもらたっす！","ENG":"Chief Maid! Did you hear! Mone got a compliment!","TWN":"女僕長，你有聽到嗎？莫妮被稱讚咧！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후후, 그래요. 모네도 이제 어엿한 메이드네요.","JPN":"ふふ、そうですね。モネももう立派なメイドです。","ENG":"Ha ha. That I did. Now you're a real maid, Mone.","TWN":"呵呵，對呀，你現在也是個扎扎實實的女僕囉。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그래서 말인데 우리 회사와 전속 계약을 맺는 건 어때요?","JPN":"それでなんですけれど、私の会社と専属契約をしてもらえないかしら？","ENG":"Speaking of... How would you like to make an exclusive contract with us?","TWN":"我是想問，你有意願和我們公司簽訂專屬契約嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"찾는 곳이 많겠지만, 안정적인 수입원이라고 생각하면 나쁘지 않은 제안 아닌가요?","JPN":"依頼は多いでしょうけど、安定的な収入源だと思えば悪くない提案だと思うわ。","ENG":"I know you must have a lot of clients, but having a steady stream of income surely mustn't sound bad?","TWN":"我知道一定很多人找你，但若你想要有穩定的收入來源，這應該是個不錯的提議吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 이미 모시는 주인님이 계셔서 전속이라는 형식은 어려울 것 같군요.","JPN":"申し訳ありません。すでに主がおりますので、専属という形ではお受けできません。","ENG":"I'm sorry. But we already have a master we follow, so an exclusive contract would be difficult.","TWN":"很抱歉，我是有主人的，恐怕無法簽訂專屬契約。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그렇군요. 선수를 뺏긴 기분이라 조금 질투나네요.","JPN":"……そうですか。先手を打たれてしまったようで少し妬けますね。","ENG":"I see. I must admit I feel a bit envious. I wonder who the lucky person is...","TWN":"原來如此，有種人才被搶走的感覺，有點忌妒呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그 주인님이란 분도 베로니카 씨처럼 좋은 사람이겠죠?","JPN":"あなたの仕える主という方も、ベロニカさんのようにいい人なのでしょう。","ENG":"But I'm sure your master must be kindhearted and gentle like you, Veronica.","TWN":"我想那位主人，應該和貝洛妮卡一樣，是個很棒的人吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그렇슴다! 무지 재밌는 분이시지 말임다!","JPN":"そうっす！　めちゃくちゃ面白い方っすよ！","ENG":"Yup! He's really funny too, ma'am!","TWN":"沒錯唷！是位非常好玩的人唷！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……네. 저 같은 것과 비교하기 송구스러울 정도시죠.","JPN":"……はい。私のような者と比べるのが申し訳ないくらいです。","ENG":"...Yes. I would feel embarrassed if I were to be compared to someone so generous...","TWN":"……是的，不過拿我和他比，我有點自慚形穢呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CEO_EP9HALF_NULL_NULL","text":{"KOREA":"그래도 내년 이맘때 계약은 미리 비워놔 주세요. 작년처럼 두 달 내내 철야 뛰긴 싫으니까.","JPN":"それでも、来年のこの時期の契約はあらかじめ空けておいてくださいね。去年のように二か月間ずっと徹夜はしたくないわ。","ENG":"However, please leave an opening for me next year around this time in advance. I'd hate to pull an all-nighter for two months straight like last year.","TWN":"那至少請你明年這個時候可以把時間空下來，我不想像去年一樣連續二個月無法睡覺。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};